import{_ as s,C as l,o as i,c as r,j as o,E as a,a as e,a3 as g}from"./chunks/framework.BTFg6ESq.js";const b=JSON.parse('{"title":"附件转写","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/settings/transcription.md","filePath":"user-guide/tools/llm-chat/settings/transcription.md","lastUpdated":1778239080000}'),c={name:"user-guide/tools/llm-chat/settings/transcription.md"},u={id:"附件转写",tabindex:"-1"};function d(h,t,p,m,_,f){const n=l("LIcon");return i(),r("div",null,[o("h1",u,[a(n,{name:"FileText",size:"28"}),t[0]||(t[0]=e(" 附件转写 ",-1)),t[1]||(t[1]=o("a",{class:"header-anchor",href:"#附件转写","aria-label":'Permalink to "<LIcon name="FileText" size="28" /> 附件转写"'},"​",-1))]),t[2]||(t[2]=g('<p>附件转写模块是实现“全模型多模态支持”的核心。它能自动提取图片、音视频及文档中的文本，并将其注入对话上下文。</p><h2 id="基础服务与策略" tabindex="-1">基础服务与策略 <a class="header-anchor" href="#基础服务与策略" aria-label="Permalink to &quot;基础服务与策略&quot;">​</a></h2><ul><li><strong>启用转写功能</strong>: 总开关。</li><li><strong>兜底转写模型</strong>: 当图片、视频等未配置独立模型时使用的保底模型。必须具备 Vision 或 Audio 能力。</li><li><strong>转写触发策略</strong>: <ul><li><strong>智能判断 (Smart)</strong>: 仅当当前会话模型原生不支持该附件（如用 GPT-4o-mini 处理视频）时才触发。</li><li><strong>总是转写 (Always)</strong>: 无论模型能力如何，都强制提取文本。适用于需要对附件内容进行正则清洗或永久留档的场景。</li></ul></li><li><strong>自动开始</strong>: 附件拖入后立即在后台静默转写，利用你的编辑时间提前完成任务。</li></ul><h2 id="复读处理-anti-hallucination" tabindex="-1">复读处理 (Anti-Hallucination) <a class="header-anchor" href="#复读处理-anti-hallucination" aria-label="Permalink to &quot;复读处理 (Anti-Hallucination)&quot;">​</a></h2><p>针对某些模型在转写长内容时可能出现的“幻觉复读”：</p><ul><li><strong>连续重复阈值</strong>: 限制同一行/句的连续出现次数。</li><li><strong>全局片段阈值</strong>: 限制任意片段在全文中的总出现次数。</li><li><strong>白名单</strong>: 允许特定固定格式（如页码、版权声明）触发重复。</li></ul><h2 id="媒体处理与压缩" tabindex="-1">媒体处理与压缩 <a class="header-anchor" href="#媒体处理与压缩" aria-label="Permalink to &quot;媒体处理与压缩&quot;">​</a></h2><ul><li><strong>FFmpeg 路径</strong>: <ul><li><strong>说明</strong>: 配置本地 <code>ffmpeg.exe</code> 的路径。</li><li><strong>作用</strong>: 只有配置了此路径，系统才能执行音视频压缩、抽帧及格式转换。</li></ul></li><li><strong>智能切图</strong>: <ul><li><strong>说明</strong>: 自动检测长图中的空白区域并进行物理切分。</li><li><strong>优势</strong>: 解决模型对超长图（如网页长截图）识别模糊的问题。</li></ul></li><li><strong>视频压缩策略</strong>: <ul><li><strong>限制</strong>: 设置上传体积阈值（如 20MB）。</li><li><strong>加速</strong>: 支持启用 <strong>NVIDIA GPU (nvenc)</strong> 硬件加速，大幅提升大视频的处理速度。</li></ul></li></ul><h2 id="性能控制" tabindex="-1">性能控制 <a class="header-anchor" href="#性能控制" aria-label="Permalink to &quot;性能控制&quot;">​</a></h2><ul><li><strong>并发控制</strong>: 设置同时进行的任务数。建议设为 3-5，避免占用过多系统资源。</li><li><strong>执行延迟</strong>: 任务开始前的随机等待时间，有效规避 API 的 <strong>429 (Too Many Requests)</strong> 限制。</li></ul><hr><div class="tip custom-block"><p class="custom-block-title">提示</p><p>关于如何配置 FFmpeg 以及针对不同附件类型的最佳 Prompt 实践，请参考 <strong><a href="./../messages/path-to-attachment">附件转写指南</a></strong>。</p></div>',12))])}const x=s(c,[["render",d]]);export{b as __pageData,x as default};
